def get_nice_description(class_num: int) -> str:
    return NICE_CLASSES_RO.get(class_num, f"Clasa {class_num}")

def get_nice_short(class_num: int) -> str:
    full = NICE_CLASSES_RO.get(class_num, "")
    if not full:
        return f"Clasa {class_num}"
    first = full.split(";")[0].split(",")[0]
    return first[:60].strip()
